import java.util.*;
import java.util.stream.*;

public class CodeSmellDetector {

    public record MethodInfo(String name, int lineCount, String ownerClass,
                              List<String> accessedClasses) {}
    public record ClassInfo(String name, int methodCount, int fieldCount) {}

    private final List<MethodInfo> methods = new ArrayList<>();
    private final List<ClassInfo> classes = new ArrayList<>();

    public void addMethod(MethodInfo method) { methods.add(method); }
    public void addClass(ClassInfo clazz) { classes.add(clazz); }

    public List<String> detectLongMethods(int threshold) {
        // Return names of methods with lineCount > threshold
        return methods.stream()
            .filter(m -> m.lineCount() > threshold)
            .map(MethodInfo::name)
            .collect(Collectors.toList());
    }

    public List<String> detectLargeClasses(int methodThreshold) {
        // Return names of classes with methodCount > methodThreshold
        return new ArrayList<>(); // TODO
    }

    public List<String> detectFeatureEnvy() {
        // Feature envy: method accesses more unique OTHER classes than its own class
        // A method has feature envy if accessedClasses contains more entries != ownerClass than entries == ownerClass
        return new ArrayList<>(); // TODO
    }

    public static void main(String[] args) {
        CodeSmellDetector detector = new CodeSmellDetector();

        detector.addMethod(new MethodInfo("processOrder", 120, "OrderService",
            List.of("OrderService", "UserService", "PaymentService", "InventoryService", "EmailService")));
        detector.addMethod(new MethodInfo("calculateTax", 15, "TaxService",
            List.of("TaxService", "TaxService", "TaxService")));
        detector.addMethod(new MethodInfo("sendEmail", 80, "NotificationService",
            List.of("UserService", "TemplateService")));

        detector.addClass(new ClassInfo("GodClass", 45, 20));
        detector.addClass(new ClassInfo("ServiceClass", 8, 5));

        System.out.println("Long methods (>50): " + detector.detectLongMethods(50));
        System.out.println("Large classes (>10): " + detector.detectLargeClasses(10));
        System.out.println("Feature envy: " + detector.detectFeatureEnvy());
    }
}

import java.util.*;

public class SolidPrinciplesChecker {

    public record ClassDesign(
        String name,
        int responsibilityCount,      // how many distinct concerns the class handles
        boolean implementsInterface,   // whether it implements an interface
        boolean dependsOnConcretes,    // true if it directly instantiates dependencies (new FooImpl())
        int publicMethodCount
    ) {}

    public record ComplianceReport(
        String className,
        boolean srp,   // Single Responsibility
        boolean ocp,   // Open/Closed (via interface)
        boolean dip,   // Dependency Inversion
        int score      // 0-3, one point per passed check
    ) {}

    public ComplianceReport check(ClassDesign design) {
        boolean srp = design.responsibilityCount() <= 1;
        boolean ocp = design.implementsInterface();
        boolean dip = !design.dependsOnConcretes();
        int score = (srp ? 1 : 0) + (ocp ? 1 : 0) + (dip ? 1 : 0);
        return new ComplianceReport(design.name(), srp, ocp, dip, score);
    }

